import{_ as e,o as a,c as d,ag as o}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Metadata","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/100_metadata.md","filePath":"10_core/30_data/100_metadata.md"}'),r={name:"10_core/30_data/100_metadata.md"};function i(c,t,n,s,l,h){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h1><h2 id="metadata-philosophy" tabindex="-1">Metadata Philosophy <a class="header-anchor" href="#metadata-philosophy" aria-label="Permalink to &quot;Metadata Philosophy&quot;">​</a></h2><p>Metadata is not decoration. Metadata is the <strong>minimum structure required</strong> for the system to understand what something is, where it belongs, how it relates, and whether it can be trusted.</p><p>Metadata must be:</p><ul><li><strong>Incremental</strong> — builds up over the pipeline, not all at once</li><li><strong>Auditable</strong> — every change is traceable</li><li><strong>Structured</strong> — stored in canonical fields, not free-text blobs</li><li><strong>Attached to canonical identity</strong> — orphaned metadata is useless</li><li><strong>Preserved through movement and transformation</strong></li></ul><h2 id="minimum-metadata-classes" tabindex="-1">Minimum Metadata Classes <a class="header-anchor" href="#minimum-metadata-classes" aria-label="Permalink to &quot;Minimum Metadata Classes&quot;">​</a></h2><h3 id="identity-metadata" tabindex="-1">Identity Metadata <a class="header-anchor" href="#identity-metadata" aria-label="Permalink to &quot;Identity Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>canonical_id</code></td><td>UUID or ULID — the machine truth</td></tr><tr><td><code>domain_prefix</code></td><td>Namespace grouping (e.g. <code>BBR4821</code>)</td></tr><tr><td><code>short_code</code></td><td>Q + 6 hex — human-visible code</td></tr><tr><td><code>checksum</code></td><td>SHA-256 fingerprint</td></tr></tbody></table><h3 id="source-metadata" tabindex="-1">Source Metadata <a class="header-anchor" href="#source-metadata" aria-label="Permalink to &quot;Source Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>source_type</code></td><td>How it entered (watcher, upload, sync)</td></tr><tr><td><code>source_path</code></td><td>Where it came from</td></tr><tr><td><code>origin_event</code></td><td>What triggered ingest</td></tr><tr><td><code>original_filename</code></td><td>Pre-normalization name</td></tr><tr><td><code>imported_by</code></td><td>User or system that imported</td></tr><tr><td><code>ingest_timestamp</code></td><td>When registration occurred</td></tr></tbody></table><h3 id="structural-metadata" tabindex="-1">Structural Metadata <a class="header-anchor" href="#structural-metadata" aria-label="Permalink to &quot;Structural Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>mime_type</code></td><td>Detected MIME type</td></tr><tr><td><code>extension</code></td><td>Lowercase file extension</td></tr><tr><td><code>chunk_count</code></td><td>Number of chunks generated</td></tr><tr><td><code>page_count</code></td><td>Pages if applicable</td></tr><tr><td><code>parser_method</code></td><td>Which parser was used</td></tr><tr><td><code>extraction_method</code></td><td>How text was obtained</td></tr></tbody></table><h3 id="semantic-metadata" tabindex="-1">Semantic Metadata <a class="header-anchor" href="#semantic-metadata" aria-label="Permalink to &quot;Semantic Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>document_type</code></td><td>Inferred type (tax return, contract, etc.)</td></tr><tr><td><code>inferred_entities</code></td><td>Extracted entities</td></tr><tr><td><code>tax_year</code></td><td>If applicable</td></tr><tr><td><code>matter_or_case</code></td><td>Associated case if applicable</td></tr><tr><td><code>tags</code></td><td>Classification tags</td></tr><tr><td><code>confidence</code></td><td>AI classification confidence score</td></tr></tbody></table><h3 id="lifecycle-metadata" tabindex="-1">Lifecycle Metadata <a class="header-anchor" href="#lifecycle-metadata" aria-label="Permalink to &quot;Lifecycle Metadata&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>status</code></td><td>Current pipeline state</td></tr><tr><td><code>review_state</code></td><td>Awaiting, reviewed, confirmed</td></tr><tr><td><code>route_state</code></td><td>Suggested, confirmed, overridden</td></tr><tr><td><code>storage_path</code></td><td>Current physical location</td></tr><tr><td><code>created_at</code></td><td>Creation timestamp</td></tr><tr><td><code>updated_at</code></td><td>Last modified timestamp</td></tr></tbody></table><h2 id="automation-gate" tabindex="-1">Automation Gate <a class="header-anchor" href="#automation-gate" aria-label="Permalink to &quot;Automation Gate&quot;">​</a></h2><blockquote><p><strong>Minimum metadata required before any automation proceeds</strong>: canonical_id, domain_prefix, short_code, source_path, ingest_timestamp, mime_type, status.</p></blockquote><p>If these fields are absent, the pipeline must halt and flag the record as incomplete.</p><h2 id="content-metadata-profile-front-matter" tabindex="-1">Content Metadata Profile (Front Matter) <a class="header-anchor" href="#content-metadata-profile-front-matter" aria-label="Permalink to &quot;Content Metadata Profile (Front Matter)&quot;">​</a></h2><p>For flat files, notes, and unstructured assets, an optional <strong>front matter</strong> block may be applied. The specification is strictly governed by <code>standards/content_metadata_profile.yaml</code>.</p><blockquote><p><strong>CRITICAL DOCTRINE</strong>: Front matter is <strong>Supportive Metadata</strong>. It is NEVER the system of record.</p><ul><li>Canonical identity comes from QiArchive.</li><li>Schema placement comes from the Pipeline.</li><li>Node topology comes from the Graph.</li></ul><p>A document cannot change its database relationships purely by altering its front matter tags.</p></blockquote><p>Common supportive fields defined in the profile include:</p><ul><li><code>status</code>: Content-level draft/review state.</li><li><code>sensitivity</code> / <code>classification</code>: Governed by <code>registry/sensitivity_classification.yaml</code>.</li><li><code>realm_label</code>: An optional UI/UX workspace filter (e.g., <code>personal</code>, <code>work</code>, <code>legal</code>) governed by <code>registry/workspace_realms.yaml</code>. Realms do not dictate physical placement, tenant isolation, or schema mapping.</li></ul>',24)])])}const u=e(r,[["render",i]]);export{p as __pageData,u as default};
